class Solution {
public:
    string arrangeWords(string text) {
        vector<pair<int, int>> words;
        int n = text.size();
        int start = 0;
        for (int i = 0; i < n; ++i) {
            if (text[i] == ' ') {
                words.emplace_back(i - start, start);
                start = i + 1;
            }
        }
        words.emplace_back(n - start, start);

        sort(words.begin(), words.end());

        string result;
        for (int i = 0; i < words.size(); ++i) {
            int idx = words[i].second;
            if (i == 0) {
                result += toupper(text[idx]);
                result += text.substr(idx + 1, words[i].first - 1);
            } else {
                result += ' ';
                result += text.substr(idx, words[i].first);
            }
        }
        return result;
    }
};
